1	/**
2	 * Shipment Request Validator
3	 *
4	 * Rules (derived from acceptance criteria AC1–AC7):
5	 *   AC1: All required fields present and valid → { valid: true, errors: [] }
6	 *   AC2: recipient_name missing or empty → REQUIRED error
7	 *   AC3: weight_kg is 0 or negative → MUST_BE_POSITIVE error
8	 *   AC4: weight_kg > 1000 → EXCEEDS_MAX error
9	 *   AC5: shipment_type "express" + saturday_delivery not provided → REQUIRED_FOR_EXPRESS
10	 *   AC6: shipment_type "standard" + saturday_delivery provided → NOT_APPLICABLE_FOR_STANDARD
11	 *   AC7: All errors are collected (no fail-fast) — every failing rule fires independently
12	 */
13	
14	export type ShipmentType = "express" | "standard";
15	
16	export interface ShipmentRequest {
17	  recipient_name?: string;
18	  weight_kg?: number;
19	  shipment_type?: ShipmentType;
20	  saturday_delivery?: boolean;
21	}
22	
23	export interface ValidationError {
24	  field: string;
25	  code: string;
26	}
27	
28	export interface ValidationResult {
29	  valid: boolean;
30	  errors: ValidationError[];
31	}
32	
33	export function validateShipmentRequest(
34	  input: ShipmentRequest
35	): ValidationResult {
36	  const errors: ValidationError[] = [];
37	
38	  // AC2: recipient_name must be present and non-empty
39	  if (
40	    input.recipient_name === undefined ||
41	    input.recipient_name === null ||
42	    input.recipient_name.trim() === ""
43	  ) {
44	    errors.push({ field: "recipient_name", code: "REQUIRED" });
45	  }
46	
47	  // AC3: weight_kg must be positive (> 0)
48	  if (input.weight_kg !== undefined && input.weight_kg <= 0) {
49	    errors.push({ field: "weight_kg", code: "MUST_BE_POSITIVE" });
50	  }
51	
52	  // AC4: weight_kg must not exceed 1000
53	  if (input.weight_kg !== undefined && input.weight_kg > 1000) {
54	    errors.push({ field: "weight_kg", code: "EXCEEDS_MAX" });
55	  }
56	
57	  // AC5: express shipments require saturday_delivery to be explicitly provided
58	  if (
59	    input.shipment_type === "express" &&
60	    input.saturday_delivery === undefined
61	  ) {
62	    errors.push({ field: "saturday_delivery", code: "REQUIRED_FOR_EXPRESS" });
63	  }
64	
65	  // AC6: standard shipments cannot specify saturday_delivery
66	  if (
67	    input.shipment_type === "standard" &&
68	    input.saturday_delivery !== undefined
69	  ) {
70	    errors.push({
71	      field: "saturday_delivery",
72	      code: "NOT_APPLICABLE_FOR_STANDARD",
73	    });
74	  }
75	
76	  return {
77	    valid: errors.length === 0,
78	    errors,
79	  };
80	}
