1	/**
2	 * Tax brackets:
3	 *   income <= 0          : throws INVALID_INCOME
4	 *   0 < income < 10_000  : 0%  (tax = 0)
5	 *   10_000 <= income <= 50_000  : 10% flat
6	 *   50_001 <= income <= 150_000 : 25% flat
7	 *   income > 150_000            : 40% flat
8	 */
9	
10	export class TaxError extends Error {
11	  constructor(
12	    public readonly code: string,
13	    message: string
14	  ) {
15	    super(message);
16	    this.name = "TaxError";
17	  }
18	}
19	
20	export function calculateTax(income: number): number {
21	  if (income <= 0) {
22	    throw new TaxError(
23	      "INVALID_INCOME",
24	      `Income must be a positive number, received: ${income}`
25	    );
26	  }
27	
28	  if (income < 10_000) {
29	    return 0;
30	  }
31	
32	  if (income <= 50_000) {
33	    return income * 0.10;
34	  }
35	
36	  if (income <= 150_000) {
37	    return income * 0.25;
38	  }
39	
40	  return income * 0.40;
41	}
