1	// ─── Domain Types ────────────────────────────────────────────────────────────
2	
3	export type SeatStatus = "available" | "reserved";
4	
5	export interface Seat {
6	  id: string;
7	  status: SeatStatus;
8	}
9	
10	export interface Reservation {
11	  seatId: string;
12	  userId: string;
13	  reservedAt: Date;
14	}
15	
16	export interface Database {
17	  findSeat(seatId: string): Promise<Seat | null>;
18	  updateSeatStatus(
19	    seatId: string,
20	    status: string,
21	    userId: string,
22	    expectedCurrentStatus: string
23	  ): Promise<boolean>;
24	}
25	
26	// ─── Error Constants ─────────────────────────────────────────────────────────
27	
28	export class ReservationError extends Error {
29	  constructor(
30	    public readonly code: "SEAT_NOT_FOUND" | "SEAT_ALREADY_RESERVED",
31	    message: string
32	  ) {
33	    super(message);
34	    this.name = "ReservationError";
35	  }
36	}
37	
38	export const SEAT_NOT_FOUND = "SEAT_NOT_FOUND" as const;
39	export const SEAT_ALREADY_RESERVED = "SEAT_ALREADY_RESERVED" as const;
40	
41	// ─── Implementation ───────────────────────────────────────────────────────────
42	
43	/**
44	 * Reserves a seat for a user.
45	 *
46	 * Uses optimistic locking via `updateSeatStatus` to handle concurrent calls
47	 * safely: if two callers read the same "available" seat simultaneously, only
48	 * the first `updateSeatStatus` will succeed (expectedCurrentStatus matches);
49	 * the second will receive `false` and throw SEAT_ALREADY_RESERVED.
50	 *
51	 * @throws {ReservationError} SEAT_NOT_FOUND       — seat does not exist
52	 * @throws {ReservationError} SEAT_ALREADY_RESERVED — seat is taken or lost a
53	 *                                                    concurrency race
54	 */
55	export async function reserveSeat(
56	  seatId: string,
57	  userId: string,
58	  db: Database
59	): Promise<Reservation> {
60	  // AC4: seat must exist
61	  const seat = await db.findSeat(seatId);
62	  if (seat === null) {
63	    throw new ReservationError(SEAT_NOT_FOUND, `Seat '${seatId}' not found`);
64	  }
65	
66	  // AC2: seat must be available
67	  if (seat.status !== "available") {
68	    throw new ReservationError(
69	      SEAT_ALREADY_RESERVED,
70	      `Seat '${seatId}' is already reserved`
71	    );
72	  }
73	
74	  // AC1 + AC3: attempt atomic transition via optimistic locking.
75	  // If another caller reserved the seat between our findSeat and this call,
76	  // updateSeatStatus returns false because the current status no longer matches
77	  // the expectedCurrentStatus we recorded ("available").
78	  const updated = await db.updateSeatStatus(
79	    seatId,
80	    "reserved",
81	    userId,
82	    seat.status // expectedCurrentStatus = "available"
83	  );
84	
85	  if (!updated) {
86	    // Lost the concurrency race — another reservation won
87	    throw new ReservationError(
88	      SEAT_ALREADY_RESERVED,
89	      `Seat '${seatId}' was reserved by another request`
90	    );
91	  }
92	
93	  return {
94	    seatId,
95	    userId,
96	    reservedAt: new Date(),
97	  };
98	}
99

