54	// ─── Core Function ────────────────────────────────────────────────────────────
55	
56	/**
57	 * Processes a payment by:
58	 *  1. Running a fraud check (throws FRAUD_DETECTED if flagged, FRAUD_SERVICE_UNAVAILABLE on network error)
59	 *  2. Charging the payment gateway (throws PAYMENT_DECLINED on decline, GATEWAY_UNAVAILABLE on network error)
60	 *  3. Returning { success: true, transaction_id } on approval
61	 *
62	 * The payment gateway is NEVER called when the fraud check flags or fails.
63	 */
64	export async function processPayment(
65	  input: PaymentInput,
66	  fraudService: FraudService,
67	  gateway: PaymentGateway
68	): Promise<PaymentResult> {
69	  // ── Step 1: Fraud check ───────────────────────────────────────────────────
70	  let fraudResult: FraudCheckResult;
71	  try {
72	    fraudResult = await fraudService.check(input);
73	  } catch (err) {
74	    throw new PaymentError(
75	      "FRAUD_SERVICE_UNAVAILABLE",
76	      "Fraud check service is unavailable",
77	      err
78	    );
79	  }
80	
81	  if (fraudResult.flagged) {
82	    throw new PaymentError("FRAUD_DETECTED", "Payment flagged as fraudulent");
83	  }
84	
85	  // ── Step 2: Charge gateway ────────────────────────────────────────────────
86	  let gatewayResult: GatewayResult;
87	  try {
88	    gatewayResult = await gateway.charge(input);
89	  } catch (err) {
90	    throw new PaymentError(
91	      "GATEWAY_UNAVAILABLE",
92	      "Payment gateway is unavailable",
93	      err
94	    );
95	  }
96	
97	  if (!gatewayResult.approved) {
98	    throw new PaymentError(
99	      "PAYMENT_DECLINED",
100	      gatewayResult.decline_reason ?? "Payment declined"
101	    );
102	  }
103	
104	  // ── Step 3: Return success ────────────────────────────────────────────────
105	  return {
106	    success: true,
107	    transaction_id: gatewayResult.transaction_id!,
108	  };
109	}
