1	import { AppError } from "../shared/app-error";
2	import { Subscription } from "./subscription";
3	import { SubscriptionRepository } from "./subscription-repository";
4	
5	const THIRTY_DAYS_MS = 2_592_000_000;
6	
7	function generateId(): string {
8	  return Math.random().toString(36).slice(2) + Math.random().toString(36).slice(2);
9	}
10	
11	export class SubscriptionService {
12	  constructor(private readonly repo: SubscriptionRepository) {}
13	
14	  /**
15	   * Creates a new active subscription for the given user and plan.
16	   * AC1: status is "active"; renewalDate is now + 30 days.
17	   */
18	  createSubscription(userId: string, planId: string): Subscription {
19	    const now = Date.now();
20	    const subscription: Subscription = {
21	      id: generateId(),
22	      userId,
23	      planId,
24	      status: "active",
25	      createdAt: now,
26	      renewalDate: now + THIRTY_DAYS_MS,
27	    };
28	    this.repo.save(subscription);
29	    return subscription;
30	  }
31	
32	  /**
33	   * Returns the subscription with the given ID.
34	   * AC2: returns subscription when found.
35	   * AC3: throws SUBSCRIPTION_NOT_FOUND when not found.
36	   */
37	  getSubscription(id: string): Subscription {
38	    const subscription = this.repo.findById(id);
39	    if (subscription === null) {
40	      throw new AppError("SUBSCRIPTION_NOT_FOUND", `Subscription "${id}" was not found.`);
41	    }
42	    return subscription;
43	  }
44	
45	  /**
46	   * Cancels an active subscription.
47	   * AC4: sets status to "cancelled" and records cancellationDate.
48	   * AC5: throws SUBSCRIPTION_ALREADY_CANCELLED if already cancelled.
49	   */
50	  cancelSubscription(id: string): Subscription {
51	    const subscription = this.getSubscription(id);
52	
53	    if (subscription.status === "cancelled") {
54	      throw new AppError(
55	        "SUBSCRIPTION_ALREADY_CANCELLED",
56	        `Subscription "${id}" is already cancelled.`
57	      );
58	    }
59	
60	    const updated: Subscription = {
61	      ...subscription,
62	      status: "cancelled",
63	      cancellationDate: Date.now(),
64	    };
65	    this.repo.save(updated);
66	    return updated;
67	  }
68	
69	  /**
70	   * Renews an active subscription by pushing renewalDate forward 30 days.
71	   * AC6: sets renewalDate to now + 30 days for active subscriptions.
72	   * AC7: throws CANNOT_RENEW_CANCELLED for cancelled subscriptions.
73	   */
74	  renewSubscription(id: string): Subscription {
75	    const subscription = this.getSubscription(id);
76	
77	    if (subscription.status === "cancelled") {
78	      throw new AppError(
79	        "CANNOT_RENEW_CANCELLED",
80	        `Cannot renew subscription "${id}" because it is cancelled.`
81	      );
82	    }
83	
84	    const updated: Subscription = {
85	      ...subscription,
86	      renewalDate: Date.now() + THIRTY_DAYS_MS,
87	    };
88	    this.repo.save(updated);
89	    return updated;
90	  }
91	
92	  /**
93	   * Returns all subscriptions (active and cancelled) for the given user.
94	   * AC8: returns every subscription regardless of status.
95	   */
96	  listSubscriptions(userId: string): Subscription[] {
97	    return this.repo.findByUserId(userId);
98	  }
99	}
